module.exports = function(eleventyConfig) {

  // Pass through static files unchanged
  eleventyConfig.addPassthroughCopy("src/css");
  eleventyConfig.addPassthroughCopy("src/images");
  eleventyConfig.addPassthroughCopy({"src/c3logo.png": "c3logo.png"});
  eleventyConfig.addPassthroughCopy({"src/c3-logo.png": "c3-logo.png"});
  eleventyConfig.addPassthroughCopy({"src/c3-og-banner.png": "c3-og-banner.png"});
  // sitemap.xml retired in task-84. It was a passthrough-only file, last regenerated by hand
  // on 25 June and never rebuilt, so it went stale: it duplicated 148 blog URLs already in
  // sitemap-blog.xml, listed 9 blog URLs that now 301-redirect, and was the ONLY source for
  // the 43 /ev-calculator/* pages, which are now carried by sitemap-static.mjs.
  eleventyConfig.addPassthroughCopy({"sitemap-index.xml": "sitemap-index.xml"});
  eleventyConfig.addPassthroughCopy({"sitemap-cards.xml": "sitemap-cards.xml"});
  // sitemap-cards-2.xml retired in task-82: MTG's eligible set (AU$1.00+, ~10,500 URLs) now
  // fits in a single file, well inside Google's 50,000-per-sitemap limit.
  // sitemap-blog.xml is generated by src/sitemap-blog.njk (Eleventy template), not a static passthrough.
  // Per-game sitemaps (pokemon/yugioh/lorcana/onepiece/riftbound/dragonball/starwars)
  // are served at runtime by /api/sitemap-* Functions, no static passthrough needed.
  eleventyConfig.addPassthroughCopy({"robots.txt": "robots.txt"});
  eleventyConfig.addPassthroughCopy({"llms.txt": "llms.txt"});

  // IndexNow ownership key. IndexNow verifies the caller owns the host by fetching this file
  // at https://cardsoncardsoncards.com.au/<key>.txt and matching its contents to the key sent
  // in the payload, so it MUST be served from the site root. The same value is stored as the
  // INDEXNOW_KEY Netlify env var, which sync-indexnow-ping.mjs reads; it is not hardcoded twice.
  eleventyConfig.addPassthroughCopy({"src/5cfc6acc94f0967802d3ca69b1198b8f.txt": "5cfc6acc94f0967802d3ca69b1198b8f.txt"});
  eleventyConfig.addPassthroughCopy({"favicon.ico": "favicon.ico"});
  eleventyConfig.addPassthroughCopy({"ev-calculator": "ev-calculator"});
  eleventyConfig.addPassthroughCopy({"quizzes": "quizzes"});
  eleventyConfig.addPassthroughCopy({"netlify": "netlify"});
  eleventyConfig.addPassthroughCopy({"netlify.toml": "netlify.toml"});

  // Passthrough src HTML files directly to _site root
  eleventyConfig.addPassthroughCopy({"src/index.html": "index.html"});
  eleventyConfig.addPassthroughCopy({"src/shop.html": "shop.html"});
  eleventyConfig.addPassthroughCopy({"src/contact.html": "contact.html"});
  eleventyConfig.addPassthroughCopy({"src/tracker.html": "tracker.html"});
  eleventyConfig.addPassthroughCopy({"src/vip.html": "vip.html"});
  eleventyConfig.addPassthroughCopy({"src/ev-calculator.html": "ev-calculator.html"});
  eleventyConfig.addPassthroughCopy({"src/mtg-strixhaven.html": "mtg-strixhaven.html"});
  eleventyConfig.addPassthroughCopy({"src/content-engine.html": "content-engine.html"});
  eleventyConfig.addPassthroughCopy({"src/dashboard.html": "dashboard.html"});
  eleventyConfig.addPassthroughCopy({"src/cards.html": "cards.html"});
  eleventyConfig.addPassthroughCopy({"src/legal.html": "legal.html"});
  eleventyConfig.addPassthroughCopy({"src/methodology.html": "methodology.html"});
  eleventyConfig.addPassthroughCopy({"src/calendar.html": "calendar.html"});
  eleventyConfig.addPassthroughCopy({"src/generators.html": "generators.html"});
  eleventyConfig.addPassthroughCopy({"src/quizzes.html": "quizzes.html"});
  eleventyConfig.addPassthroughCopy({"src/dnd.html": "dnd.html"});
  // New hub pages
  eleventyConfig.addPassthroughCopy({"src/tools.html": "tools.html"});
  eleventyConfig.addPassthroughCopy({"src/play.html": "play.html"});
  eleventyConfig.addPassthroughCopy({"src/pricing.html": "pricing.html"});
  eleventyConfig.addPassthroughCopy({"src/subscribe.html": "subscribe.html"});
  // Landing page for the QR code on the parcel insert card. Direct-visit only, not in the nav.
  eleventyConfig.addPassthroughCopy({"src/welcome.html": "welcome.html"});

  // Only blog posts (tagged "post") use the permalink rule
  eleventyConfig.addGlobalData("eleventyComputed", {
    permalink: data => {
      if (data.permalink) return data.permalink;
      if (data.tags && data.tags.includes('post')) {
        return `/blog/${data.page.fileSlug.replace(/^p\d+-/, '')}/`;
      }
      return false;
    }
  });

  eleventyConfig.addCollection("post", function(collectionApi) {
    return collectionApi.getFilteredByTag("post").sort((a, b) => b.date - a.date);
  });

  eleventyConfig.addFilter("dateDisplay", (dateObj) => {
    return new Date(dateObj).toLocaleDateString("en-AU", {
      day: "numeric",
      month: "long",
      year: "numeric"
    });
  });

  eleventyConfig.addFilter("dateISO", (dateObj) => {
    return new Date(dateObj).toISOString().split("T")[0];
  });

  eleventyConfig.addFilter("tagClass", (category) => {
    const map = {
      "buying-guides":"tag-guide","value-and-worth":"tag-guide",
      "product-comparisons":"tag-guide","selling-and-money":"tag-guide",
      "beginner-guides":"tag-game","general-tcg":"tag-game",
      "tools-and-trackers":"tag-tools","accessories":"tag-accessory"
    };
    return map[category] || "tag-guide";
  });

  eleventyConfig.addFilter("tagLabel", (category) => {
    const map = {
      "buying-guides":"Buying Guide","value-and-worth":"Buying Guide",
      "product-comparisons":"Buying Guide","selling-and-money":"Selling Guide",
      "beginner-guides":"Game Guide","general-tcg":"Game Guide",
      "tools-and-trackers":"Free Tools","accessories":"Accessories"
    };
    return map[category] || "Guide";
  });

  return {
    dir: {
      input: "src",
      output: "_site",
      includes: "_includes",
      layouts: "_includes/layouts"
    },
    htmlTemplateEngine: "njk",
    markdownTemplateEngine: "njk"
  };
};
